#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int s[2],f,v,sum,rev;
}t[N];

int n,m,stk[N];

void pushrev(int x){
    swap(t[x].s[0],t[x].s[1]);
    t[x].rev^=1;
}

void pushup(int x){
    t[x].sum=t[t[x].s[0]].sum^t[x].v^t[t[x].s[1]].sum;
}

void pushdown(int x){
    if(t[x].rev){
        if(t[x].s[0]) pushrev(t[x].s[0]);
        if(t[x].s[1]) pushrev(t[x].s[1]);
        t[x].rev=0;
    }
}

int isroot(int x){
    return t[t[x].f].s[0]!=x && t[t[x].f].s[1]!=x;
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(t[y].s[1]==x);
    if(!isroot(y)) t[z].s[t[z].s[1]==y]=x;
    t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x){
    int top=0,u=x;
    stk[++top]=u;
    while(!isroot(u)) stk[++top]=u=t[u].f;
    while(top) pushdown(stk[top--]);
    while(!isroot(x)){
        int y=t[x].f,z=t[y].f;
        if(!isroot(y))
            if((t[y].s[1]==x)^(t[z].s[1]==y)) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
}

void Access(int x){
    int z=x;
    for(int y=0;x;y=x,x=t[x].f){
        Splay(x);
        t[x].s[1]=y,pushup(x);
    }
    Splay(z);
}

void Makeroot(int x){
    Access(x);
    pushrev(x);
}

int findroot(int x){
    Access(x);
    while(t[x].s[0]) pushdown(x),x=t[x].s[0];
    Splay(x);
    return x;
}

void Split(int x,int y){
    Makeroot(x);
    Access(y);
}

void Link(int x,int y){
    Makeroot(x);
    if(findroot(y)!=x) t[x].f=y;
}

void Cut(int x,int y){
    Makeroot(x);
    if(findroot(y)==x && t[x].s[1]==y && !t[y].s[0]){
        t[x].s[1]=t[y].f=0;
        pushup(x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&t[i].v);
    while(m--){
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==0){
            Split(x,y);
            printf("%d\n",t[y].sum);
        }else if(op==1)
            Link(x,y);
        else if(op==2)
            Cut(x,y);
        else{
            Splay(x);
            t[x].v=y,pushup(x);
        }
    }
    return 0;
}
